TCP_CLIENT_CONNECT(server_ip, server_port)
BEGIN
 // Create socket
 client_socket = socket(AF_INET, SOCK_STREAM)

 // Prepare server address
 server_addr.ip = server_ip
 server_addr.port = server_port

 // Initiate connection (sends SYN)
 connect(client_socket, server_addr)
 // State: SYN_SENT

 // Wait for server's SYN-ACK
 receive(client_socket, response)
 // Verify: response.ack == local_seq + 1
 // Verify: response.syn == TRUE

 // Send ACK (completes handshake)
 send(client_socket, ACK_flag + ack=server_seq+1)
 // State: ESTABLISHED

 RETURN client_socket
END

TCP_SERVER_LISTEN(port)
BEGIN
 // Create listening socket
 listen_socket = socket(AF_INET, SOCK_STREAM)

 // Bind to port
 server_addr.port = port
 bind(listen_socket, server_addr)
 // State: CLOSED -> LISTEN

 // Start listening for connections
 listen(listen_socket, backlog_size)
 // State: LISTEN

 // Accept incoming connections
 WHILE TRUE DO
 client_socket = accept(listen_socket, client_addr)
 // State: SYN_RCVD -> ESTABLISHED
 // (Three-way handshake completes automatically)

 // Handle client in new thread/process
 HANDLE_CLIENT(client_socket)
 END WHILE
END

TCP_CLOSE_CONNECTION(socket)
BEGIN
 // Send FIN (initiate close)
 send(socket, FIN + seq=current_seq)
 // State: FIN_WAIT_1

 // Wait for ACK from server
 ack = receive(socket)
 // State: FIN_WAIT_2

 // Wait for server's FIN
 fin_segment = receive(socket)
 // Verify: fin_segment.flag == FIN

 // Send final ACK
 send(socket, ACK + ack=fin_segment.seq+1)
 // State: TIME_WAIT

 // Wait for 2MSL (Maximum Segment Lifetime)
 wait(2 * MSL)
 // State: CLOSED

 close(socket)
END

TCP_SERVER_CLOSE(socket)
BEGIN
 // Receive client's FIN
 fin = receive(socket)
 send(socket, ACK + ack=fin.seq+1)
 // State: CLOSE_WAIT

 // Continue sending remaining data if any
 send_remaining_data(socket)

 // Send FIN when done
 send(socket, FIN + seq=current_seq)
 // State: LAST_ACK

 // Wait for final ACK
 ack = receive(socket)
 // State: CLOSED

 close(socket)
END
